     9→import 'package:baseball_detector_flutter/data/models/enums/app_role.dart';
    10→import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
    11→import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
    12→import 'package:baseball_detector_flutter/data/models/profile.dart';
    13→import 'package:baseball_detector_flutter/data/models/short_role_info.dart';
    14→import 'package:baseball_detector_flutter/data/models/team.dart';
    15→import 'package:baseball_detector_flutter/data/models/user_role.dart';
    16→
    17→part 'user_info.freezed.dart';
    18→part 'user_info.g.dart';
    19→
    20→// This typedef must be in this file because json_serializable crashes
    21→typedef DomainAccessibleContents = Map<RoleLevel, ShortRoleInfo>;
    22→typedef TeamAccessibleContents = Map<RoleDomain, DomainAccessibleContents>;
    23→typedef UserAccessibleContents = Map<String, TeamAccessibleContents>;
    24→
    25→const allTeams = 'all';
    26→
    27→// dummy class for generating TeamAccessibleContents serializer
    28→@JsonSerializable(explicitToJson: true)
    29→class _UserAccessContents {
    30→  final UserAccessibleContents data;
    31→
    32→  const _UserAccessContents(this.data);
    33→}
    34→
    35→class UserAccessContentsConverter {
    36→  UserAccessContentsConverter._();
    37→
    38→  static UserAccessibleContents fromJson(Map<String, dynamic> json) =>
    39→      _$UserAccessContentsFromJson({'data': json}).data;
    40→}
    41→
    42→extension UserAccessibleContentsExt on UserAccessibleContents {
    43→  bool hasPrivilegesFor(
    44→    String teamId,
    45→    RoleDomain domain,
    46→    RoleLevel level,
    47→    bool shouldCheckTeamCrossing,
    48→  ) {
    49→    final shortRoleInfo = (this[teamId] ?? this[allTeams])?[domain]?[level];
    50→    if (shortRoleInfo == null) {
    51→      return false;
    52→    }
    53→
    54→    return shouldCheckTeamCrossing
    55→        ? shortRoleInfo.isAccessible && shortRoleInfo.isTeamCrossing
    56→        : shortRoleInfo.isAccessible;
    57→  }
    58→
    59→  Map<String, dynamic> toJson() =>
    60→      _$UserAccessContentsToJson(_UserAccessContents(this))['data'];
    61→}
    62→
    63→@freezed
    64→abstract class UserInfo with _$UserInfo {
    65→  const UserInfo._();
    66→
    67→  @JsonSerializable(
    68→      explicitToJson: true, fieldRename: Constants.modelFieldRename)
    69→  const factory UserInfo({
    70→    required String id,
    71→    String? email,
    72→    DateTime? deletedAt, // assumes UTC
    73→    DateTime? createdAt, // assumes UTC
    74→    DateTime? updatedAt, // assumes UTC
    75→    required Profile profile,
    76→    required UserAccessibleContents accessibleContents,
    77→    required Map<String, List<UserRole>> givenUserRoles,
    78→    required List<Team> teams,
    79→  }) = _UserInfo;
    80→
    81→  factory UserInfo.fromJson(Map<String, dynamic> json) =>
    82→      _$UserInfoFromJson(json);
    83→
    84→  bool isDeactivated(String? teamId) {
    85→    if (teamId == null) return true;
    86→    final roles = givenUserRoles[teamId];
    87→    if (roles == null || roles.isEmpty) return true;
    88→    // Check if the user has any active role in the team
    89→    return roles.first.deleteFlag;
    90→  }
    91→
    92→  AppRole? getAppRoleFor(String teamId) {
    93→    // First check for direct team assignment
    94→    final directRole = givenUserRoles[teamId]?.firstOrNull?.roleGroup.name;
    95→    if (directRole != null) {
    96→      return directRole;
    97→    }
    98→
    99→    // For super_admin users, check if they have super_admin role for any team
   100→    // If so, they should have super_admin privileges for all teams
   101→    final hasSuperAdminRole = givenUserRoles.values
   102→        .expand((roles) => roles)
   103→        .any((userRole) => userRole.roleGroup.name == AppRole.superAdmin);
   104→    if (hasSuperAdminRole) return AppRole.superAdmin;
   105→
   106→    // For super readers, check if they have super_reader role for any team
   107→    final hasSuperReaderRole = givenUserRoles.values
   108→        .expand((roles) => roles)
   109→        .any((userRole) => userRole.roleGroup.name == AppRole.superReader);
   110→    if (hasSuperReaderRole) return AppRole.superReader;
   111→
   112→    return null;
   113→  }
   114→
   115→  Team? getTeam(String teamId) {
   116→    return teams.where((team) => team.id == teamId).firstOrNull;
   117→  }
   118→
   119→  bool isOnlyBelongingToSingleTeam() {
   120→    // Filter out teams where the user is deactivated
   121→    final activeTeams = teams.where((team) => !isDeactivated(team.id)).toList();
   122→
   123→    if (activeTeams.length != 1) return false;
   124→    final team = activeTeams.first;
   125→    return team.isSingleUserTeam;
   126→  }
   127→}
